import React, { useState, useEffect, useMemo } from 'react';
import AccommodationSearch from './components/SearchBar/AccommodationSearch';
import FilterSidebar from './components/Filters/FilterSidebar';
import ListingGrid from './components/Listings/ListingGrid';
import { fetchAccommodations } from './utils/fetchListings';
// Requires global standard index.css to be active in the application root

const AccommodationModule = ({ initialContext }) => {
  // 1. PRIMARY SEARCH STATE (Controls the API calls)
    const [searchParams, setSearchParams] = useState({
        city: initialContext?.destinationCity || '',
            checkIn: initialContext?.arrivalDate || '',
                checkOut: '',
                    guests: 1
                      });

                        // 2. FILTER STATE (Controls the local UI sorting)
                          const [activeFilters, setActiveFilters] = useState({
                              minPrice: 0,
                                  maxPrice: 2000000,
                                      stars: [],
                                          types: [],
                                              amenities: []
                                                });

                                                  // 3. DATA STATE
                                                    const [listings, setListings] = useState([]);
                                                      const [isLoading, setIsLoading] = useState(true);
                                                        const [error, setError] = useState(null);

                                                          // 4. THE FETCH ENGINE
                                                            const executeSearch = async () => {
                                                                if (!searchParams.city) return;
                                                                    
                                                                        setIsLoading(true);
                                                                            setError(null);
                                                                                try {
                                                                                      const data = await fetchAccommodations(searchParams);
                                                                                            setListings(data);
                                                                                                } catch (err) {
                                                                                                      setError("Failed to connect to accommodation partners. Please try again.");
                                                                                                          } finally {
                                                                                                                setIsLoading(false);
                                                                                                                    }
                                                                                                                      };

                                                                                                                        // Auto-trigger search if we inherited a city from the main bus booking flow
                                                                                                                          useEffect(() => {
                                                                                                                              if (searchParams.city) {
                                                                                                                                    executeSearch();
                                                                                                                                        } else {
                                                                                                                                              setIsLoading(false);
                                                                                                                                                  }
                                                                                                                                                    }, []); // eslint-disable-line react-hooks/exhaustive-deps

                                                                                                                                                      // 5. THE INSTANT FILTERING ENGINE (Lightning fast client-side sorting)
                                                                                                                                                        const filteredListings = useMemo(() => {
                                                                                                                                                            return listings.filter(listing => {
                                                                                                                                                                  // Budget Filter
                                                                                                                                                                        if (listing.pricePerNight < activeFilters.minPrice || listing.pricePerNight > activeFilters.maxPrice) {
                                                                                                                                                                                return false;
                                                                                                                                                                                      }
                                                                                                                                                                                            
                                                                                                                                                                                                  // Star Rating Filter
                                                                                                                                                                                                        if (activeFilters.stars.length > 0 && !activeFilters.stars.includes(listing.rating)) {
                                                                                                                                                                                                                return false;
                                                                                                                                                                                                                      }
                                                                                                                                                                                                                            
                                                                                                                                                                                                                                  // Property Type Filter (Assuming API returns 'propertyType', mapping to 'types')
                                                                                                                                                                                                                                        if (activeFilters.types.length > 0 && !activeFilters.types.includes(listing.propertyType)) {
                                                                                                                                                                                                                                                // Note: For full real-world wiring, ensure propertyType is in responseSchemas.js
                                                                                                                                                                                                                                                        // return false; 
                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                          // Amenities Filter (Must have ALL selected amenities)
                                                                                                                                                                                                                                                                                if (activeFilters.amenities.length > 0) {
                                                                                                                                                                                                                                                                                        const hasAll = activeFilters.amenities.every(amenity => listing.amenities.includes(amenity));
                                                                                                                                                                                                                                                                                                if (!hasAll) return false;
                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                  return true;
                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                        }, [listings, activeFilters]);


                                                                                                                                                                                                                                                                                                                          // 6. RENDER THE MODULE
                                                                                                                                                                                                                                                                                                                            return (
                                                                                                                                                                                                                                                                                                                                <div className="ayabus-scroll-area" style={{ display: 'flex', flexDirection: 'column', gap: '24px', backgroundColor: 'var(--bg-canvas)' }}>
                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                            {/* --- MODULE HEADER --- */}
                                                                                                                                                                                                                                                                                                                                                  <div style={{ paddingBottom: '16px', borderBottom: '1px solid var(--border-subtle)' }}>
                                                                                                                                                                                                                                                                                                                                                          <h2 style={{ fontSize: '28px', fontWeight: '900', color: 'var(--text-main)', marginBottom: '8px', letterSpacing: '-0.5px' }}>
                                                                                                                                                                                                                                                                                                                                                                    Verified Stays in {searchParams.city || 'Your Destination'}
                                                                                                                                                                                                                                                                                                                                                                            </h2>
                                                                                                                                                                                                                                                                                                                                                                                    <p style={{ color: 'var(--text-muted)', fontSize: '16px', fontWeight: '500' }}>
                                                                                                                                                                                                                                                                                                                                                                                              Seamlessly book your rest. Powered by AyaBus global partners.
                                                                                                                                                                                                                                                                                                                                                                                                      </p>
                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                  {/* --- SEARCH INTERFACE --- */}
                                                                                                                                                                                                                                                                                                                                                                                                                        <AccommodationSearch 
                                                                                                                                                                                                                                                                                                                                                                                                                                searchParams={searchParams} 
                                                                                                                                                                                                                                                                                                                                                                                                                                        updateParams={setSearchParams} 
                                                                                                                                                                                                                                                                                                                                                                                                                                                onSearch={executeSearch} 
                                                                                                                                                                                                                                                                                                                                                                                                                                                      />

                                                                                                                                                                                                                                                                                                                                                                                                                                                            {/* --- ERROR BOUNDARY --- */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {error && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div style={{ padding: '16px', backgroundColor: 'var(--status-error)', color: '#FFFFFF', borderRadius: 'var(--radius-md)', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '12px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <span>⚠️</span> {error}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* --- MAIN LAYOUT (Sidebar + Content Matrix) --- */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="layout-matrix">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {/* LEFT COLLUMN: Dynamic Filter Sidebar */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <aside className="filter-column">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div style={{ position: 'sticky', top: '0', height: 'max-content', maxHeight: 'calc(100vh - 100px)' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <FilterSidebar onApplyFilters={setActiveFilters} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </aside>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {/* RIGHT COLUMN: Listings & Category Strip */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <main className="content-column">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {/* Future-Proof Feature: Horizontal Category Strip */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="ayabus-hide-scrollbar" style={{ 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        display: 'flex', 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    gap: '12px', 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                overflowX: 'auto', 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            paddingBottom: '16px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        marginBottom: '16px',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    scrollSnapType: 'x mandatory' 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {['All Stays', 'Top Rated', 'Budget Friendly', 'Luxury', 'Near Bus Station'].map((category, index) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <button 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        key={index} 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        className={`ayabus-btn ${index === 0 ? 'ayabus-btn-primary' : 'ayabus-btn-ghost'}`}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        style={{ scrollSnapAlign: 'start', borderRadius: 'var(--radius-full)', height: '36px', fontSize: '12px', whiteSpace: 'nowrap' }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {category}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {/* Results Summary */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {!isLoading && !error && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div style={{ marginBottom: '16px', fontSize: '14px', color: 'var(--text-muted)', fontWeight: '600' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        Showing {filteredListings.length} results matching your criteria
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* The Data Grid */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <ListingGrid 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              listings={filteredListings} 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          isLoading={isLoading} 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      searchCity={searchParams.city} 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </main>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {/* --- RESPONSIVE CSS INJECTION --- */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {/* Ensures flawless degradation on mobile devices while keeping dependencies to zero */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <style>{`
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .layout-matrix {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  display: flex;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            gap: 32px;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      align-items: flex-start;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                width: 100%;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .filter-column {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          flex: 0 0 300px; /* Fixed width sidebar on desktop */
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    min-width: 0;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .content-column {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              flex: 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        min-width: 0; /* Prevents flex blowouts */
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  display: flex;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            flex-direction: column;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            /* Mobile Breakpoint Adjustment */
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    @media (max-width: 992px) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              .layout-matrix {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          flex-direction: column;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              .filter-column {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          flex: 1 1 auto;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      width: 100%;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  /* On mobile, un-stick the sidebar so it flows naturally */
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      .filter-column > div {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  position: relative;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              max-height: none;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      `}</style>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            export default AccommodationModule;